INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-observability', 'Lucid Observability', 'Production monitoring: Sentry, OpenTelemetry, alerting, incident response', '5.0.0', 'operations', '[{"name":"lucid_triage","description":"Analyze a Sentry issue for severity, temporal pattern, and root cause diagnosis. Combines severity scoring, pattern detection, and keyword matching into a structured triage result.","parameters":{"type":"object","properties":{"title":{"type":"string","description":"Issue title from Sentry"},"level":{"type":"string","description":"Sentry level (fatal, error, warning, info)"},"count":{"type":"number","description":"Total event count"},"userCount":{"type":"number","description":"Affected user count"},"lastSeen":{"type":"string","description":"ISO 8601 timestamp of last occurrence"},"culprit":{"type":"string","description":"Culprit string from Sentry"},"stackTrace":{"type":"string","description":"Stack trace text"},"timestamps":{"type":"array","items":{},"description":"Array of event timestamps (ms) for temporal analysis"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["title"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_readiness","description":"Check production readiness of a service by validating environment variables against the observability checklist. Returns a score, pass/warn/fail per variable, and critical failures.","parameters":{"type":"object","properties":{"environment":{"type":"string","enum":["production","staging","development"],"description":"Target environment"},"env_vars":{"type":"object","additionalProperties":{},"description":"Environment variables to check (key/value pairs). Keys: SENTRY_DSN, SENTRY_AUTH_TOKEN, OTEL_ENABLED, OTEL_EXPORTER_OTLP_ENDPOINT, OTEL_HASH_SALT, OPENMETER_ENABLED, OPENMETER_API_KEY, DATABASE_URL, LUCID_ENV"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["env_vars"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_outbox_health","description":"Analyze OpenMeter outbox health from queue statistics. Applies thresholds to detect queue backup, dead letters, stuck leases, and zero throughput.","parameters":{"type":"object","properties":{"pending":{"type":"number","description":"Pending events (unsent, attempts < 10)"},"sent":{"type":"number","description":"Successfully sent events"},"dead_letter":{"type":"number","description":"Dead letter events (attempts >= 10)"},"leased":{"type":"number","description":"Currently leased events"},"total":{"type":"number","description":"Total events in time window"},"stuck_leases":{"type":"number","description":"Leases expired but not released"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["pending","sent","dead_letter","leased","total","stuck_leases"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_diagnose","description":"Pattern-match an error title, culprit, and stack trace against 12 known diagnosis categories (litellm_timeout, openmeter_timeout, privy_auth, mcp_server_down, network_error, timeout, auth_error, rate_limit, database_error, validation_error, memory_leak, application_error).","parameters":{"type":"object","properties":{"title":{"type":"string","description":"Error title or message"},"culprit":{"type":"string","description":"Culprit string (file/function that threw)"},"stack_trace":{"type":"string","description":"Full stack trace text"},"format":{"type":"string","enum":["json","text"],"description":"Output format"}},"required":["title"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_obs_pro","description":"Direct access to observability analysis functions. Use list_tools to see available tools, or call one directly.","parameters":{"type":"object","properties":{"tool":{"type":"string","description":"Tool name or \"list_tools\""},"params":{"type":"object","additionalProperties":{},"description":"Tool parameters"}},"required":["tool"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-predict', 'Lucid Predict', 'Prediction markets: Polymarket, Manifold, sentiment analysis, on-chain signals', '5.0.0', 'trading', '[{"name":"lucid_evaluate","description":"Evaluate a prediction market for edge and optimal position sizing. Combines EV analysis, Kelly criterion, market efficiency, and time decay into a structured verdict (BUY_YES / BUY_NO / SKIP / HEDGE).","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Market to evaluate (title, URL, or search query)"},"probability":{"type":"number","description":"Your estimated true probability (0-1). Omit to use market price."},"adjustments":{"type":"array","items":{},"description":"Bayesian adjustments [{factor, direction, magnitude, reasoning}]"},"format":{"type":"string","enum":["json","text"],"description":"Output format"},"detail":{"type":"string","enum":["full","compact"],"description":"Detail level"}},"required":["query"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_discover","description":"Scan prediction markets across all platforms to discover edge opportunities. Filters by minimum edge threshold and returns sorted by score.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search criteria (topic, category, or keyword)"},"minEdge":{"type":"number","description":"Minimum edge % to include"},"limit":{"type":"number","description":"Max results to return"},"format":{"type":"string","enum":["json","text"]}},"required":["query"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_arbitrage","description":"Detect cross-platform arbitrage opportunities by matching similar markets across Polymarket, Manifold, and Kalshi, then calculating price spreads.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Optional filter query"},"minSpread":{"type":"number","description":"Minimum spread % to report"},"format":{"type":"string","enum":["json","text"]}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_correlate","description":"[COMING SOON] Find correlated prediction markets where one has resolved but the related market hasn''t adjusted its price yet — exploiting correlation lag.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Topic or category to search"},"format":{"type":"string","enum":["json","text"]}},"required":["query"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_size","description":"Calculate optimal position sizes for a portfolio of prediction market positions using Kelly criterion with correlation adjustments.","parameters":{"type":"object","properties":{"positions":{"type":"array","items":{},"description":"Array of {price, probability, label?} objects"},"bankroll":{"type":"number","description":"Total bankroll (default from config)"},"maxFraction":{"type":"number","description":"Max fraction per position"},"format":{"type":"string","enum":["json","text"]}},"required":["positions"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_calibrate","description":"Analyze your prediction calibration using Brier score, calibration curve, and overconfidence detection. Provide an array of past forecasts with outcomes.","parameters":{"type":"object","properties":{"forecasts":{"type":"array","items":{},"description":"Array of {predictedProbability, actualOutcome (0 or 1), category?}"},"format":{"type":"string","enum":["json","text"]}},"required":["forecasts"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_pro","description":"Direct access to prediction market math functions and platform adapters. Use list_tools to see available tools, or call one directly.","parameters":{"type":"object","properties":{"tool":{"type":"string","description":"Tool name or \"list_tools\""},"params":{"type":"object","additionalProperties":{},"description":"Tool parameters"}},"required":["tool"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-propose', 'Lucid Propose', 'RFP and proposal engine: drafting, tracking, win-rate optimization', '0.1.0', 'sales', '[{"name":"propose_create_proposal","description":"Create a new proposal. Optionally use a template to pre-populate sections. Returns the created proposal with its ID.","parameters":{"type":"object","properties":{"title":{"type":"string","minLength":1},"client_name":{"type":"string","minLength":1},"client_email":{"type":"string","format":"email"},"pricing_model":{"type":"string","enum":["fixed","hourly","retainer","milestone","value_based","subscription"]},"template_id":{"type":"string"}},"required":["title","client_name","client_email","pricing_model"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_analyze_rfp","description":"Analyze RFP (Request for Proposal) content to extract requirements, evaluation criteria, deadlines, budget hints, and key themes. Provides structured analysis to guide proposal creation.","parameters":{"type":"object","properties":{"rfp_content":{"type":"string","minLength":10}},"required":["rfp_content"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_generate_section","description":"Generate an AI-ready prompt for a specific proposal section. Returns a detailed prompt that can be used to generate section content, incorporating the proposal context and company information.","parameters":{"type":"object","properties":{"proposal_id":{"type":"string","minLength":1},"section_type":{"type":"string","enum":["executive_summary","problem_statement","solution","methodology","timeline","team","pricing","case_study","references","terms","appendix","custom"]},"context":{"type":"string"}},"required":["proposal_id","section_type"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_score_proposal","description":"Score a proposal on completeness, clarity, pricing alignment, and compliance. Returns a total score (0-100) with a detailed breakdown and actionable improvement suggestions.","parameters":{"type":"object","properties":{"proposal_id":{"type":"string","minLength":1}},"required":["proposal_id"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_manage_templates","description":"Manage proposal templates: create, list, get, or update templates. Templates provide reusable section structures for consistent proposal creation.","parameters":{"type":"object","properties":{"action":{"type":"string","enum":["create","list","get","update"]},"template_id":{"type":"string"},"name":{"type":"string"},"category":{"type":"string","enum":["saas","consulting","development","marketing","design","infrastructure","general"]},"description":{"type":"string"},"sections":{"type":"array","items":{"type":"object","properties":{"section_type":{"type":"string","enum":["executive_summary","problem_statement","solution","methodology","timeline","team","pricing","case_study","references","terms","appendix","custom"]},"title":{"type":"string"},"content":{"type":"string"},"sort_order":{"type":"number"},"is_included":{"type":"boolean","default":true}},"required":["section_type","title","content","sort_order"],"additionalProperties":false}},"default_pricing":{"type":"string","enum":["fixed","hourly","retainer","milestone","value_based","subscription"]},"is_active":{"type":"boolean"}},"required":["action"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_search_content","description":"Search reusable content blocks for proposals. Find pre-written content snippets by keyword or category to accelerate proposal writing.","parameters":{"type":"object","properties":{"query":{"type":"string","minLength":1},"category":{"type":"string"}},"required":["query"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_calculate_pricing","description":"Calculate pricing breakdown based on the specified model (fixed, hourly, retainer, milestone, value_based, subscription). Provide relevant parameters for each model type.","parameters":{"type":"object","properties":{"model":{"type":"string","enum":["fixed","hourly","retainer","milestone","value_based","subscription"]},"params":{"type":"object","properties":{"hours":{"type":"number"},"rate":{"type":"number"},"contingency":{"type":"number"},"monthly_hours":{"type":"number"},"discount":{"type":"number"},"total":{"type":"number"},"items":{"type":"array","items":{"type":"object","properties":{"description":{"type":"string"},"hours":{"type":"number"},"rate":{"type":"number"}},"required":["description","hours","rate"],"additionalProperties":false}},"milestones":{"type":"array","items":{"type":"object","properties":{"name":{"type":"string"},"percentage":{"type":"number"},"description":{"type":"string"}},"required":["name","percentage"],"additionalProperties":false}}},"additionalProperties":false}},"required":["model","params"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_get_analytics","description":"Get analytics data for proposals. If proposal_id is provided, returns events for that specific proposal. Otherwise returns aggregate analytics including win rates, average deal size, and pipeline value.","parameters":{"type":"object","properties":{"proposal_id":{"type":"string"},"days":{"type":"integer","exclusiveMinimum":0,"default":30}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_compare_proposals","description":"Compare multiple proposals side-by-side. Provides scoring, value comparison, and identifies the strongest proposal across multiple dimensions.","parameters":{"type":"object","properties":{"proposal_ids":{"type":"array","items":{"type":"string"},"minItems":2}},"required":["proposal_ids"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"propose_status","description":"Check the health and configuration status of the Lucid Propose plugin. Returns plugin info, configuration state, and connectivity status.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-prospect', 'Lucid Prospect', 'Sales prospecting: lead discovery, enrichment, outreach automation', '1.0.0', 'sales', '[{"name":"lucid-prospect__prospect_find_leads","description":"Search for leads across all configured providers (Apollo, Hunter, Clearbit, Crunchbase). Returns deduplicated results with contact details and stores them in the database.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query (e.g., \"marketing managers at SaaS companies\")"},"title":{"type":"string","description":"Filter by job title (e.g., \"VP of Sales\")"},"industry":{"type":"string","enum":["technology","finance","healthcare","education","retail","manufacturing","media","real_estate","consulting","other"],"description":"Filter by industry"},"company_size":{"type":"string","enum":["1-10","11-50","51-200","201-500","501-1000","1001-5000","5000+"],"description":"Filter by company size"},"location":{"type":"string","description":"Filter by location (e.g., \"San Francisco, CA\")"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Maximum results to return"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_enrich_lead","description":"Enrich a lead by email using all available providers (Apollo, Hunter, Clearbit). Merges data from multiple sources and updates the database.","parameters":{"type":"object","properties":{"email":{"type":"string","description":"Email address of the lead to enrich"}},"required":["email"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_enrich_company","description":"Enrich a company by domain using all available providers (Apollo, Clearbit, Crunchbase). Returns comprehensive company profile including funding, tech stack, and employee data.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Company domain (e.g., \"stripe.com\")"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_find_emails","description":"Find email addresses at a company domain using Hunter.io and Apollo. Optionally filter by name. Verifies emails when possible.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Company domain to search (e.g., \"stripe.com\")"},"name":{"type":"string","description":"Filter by person name"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Maximum results"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_verify_email","description":"Verify an email address using Hunter.io or other configured providers. Checks MX records, SMTP, catch-all, and disposable status.","parameters":{"type":"object","properties":{"email":{"type":"string","description":"Email address to verify"}},"required":["email"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_build_list","description":"Create a targeted lead list (campaign) from ICP criteria. Automatically finds matching leads in the database and optionally triggers enrichment.","parameters":{"type":"object","properties":{"name":{"type":"string","description":"Name for the lead list/campaign"},"icp":{"type":"object","properties":{"industries":{"type":"array","items":{"type":"string","enum":["technology","finance","healthcare","education","retail","manufacturing","media","real_estate","consulting","other"]},"description":"Target industries"},"company_sizes":{"type":"array","items":{"type":"string","enum":["1-10","11-50","51-200","201-500","501-1000","1001-5000","5000+"]},"description":"Target company sizes"},"titles":{"type":"array","items":{"type":"string"},"description":"Target job titles"},"min_score":{"type":"number","minimum":0,"maximum":100,"description":"Minimum lead score"}},"description":"Ideal Customer Profile criteria"},"auto_enrich":{"type":"boolean","description":"Auto-enrich leads that lack enrichment data"}},"required":["name"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_score_leads","description":"Score all leads (or campaign-specific leads) using multi-factor scoring: email quality (30%), title relevance (25%), company fit (25%), engagement (10%), recency (10%). Updates scores in the database.","parameters":{"type":"object","properties":{"campaign_id":{"type":"string","description":"Score only leads in this campaign"},"min_score":{"type":"number","minimum":0,"maximum":100,"description":"Only return leads above this score"},"rescore":{"type":"boolean","description":"Re-score all leads even if already scored"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_find_companies","description":"Search for companies in the database matching criteria like industry, employee count, and keywords.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query for company name, domain, or description"},"industry":{"type":"string","enum":["technology","finance","healthcare","education","retail","manufacturing","media","real_estate","consulting","other"],"description":"Filter by industry"},"min_employees":{"type":"number","minimum":0,"description":"Minimum employee count"},"max_employees":{"type":"number","minimum":0,"description":"Maximum employee count"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_get_icp_match","description":"Calculate how well a lead (by email) or company (by domain) matches your Ideal Customer Profile. Returns a score (0-100) with detailed breakdown.","parameters":{"type":"object","properties":{"email_or_domain":{"type":"string","description":"Email address (for lead) or domain (for company) to match against ICP"},"icp":{"type":"object","properties":{"industries":{"type":"array","items":{"type":"string","enum":["technology","finance","healthcare","education","retail","manufacturing","media","real_estate","consulting","other"]}},"company_sizes":{"type":"array","items":{"type":"string","enum":["1-10","11-50","51-200","201-500","501-1000","1001-5000","5000+"]}},"titles":{"type":"array","items":{"type":"string"}},"technologies":{"type":"array","items":{"type":"string"}},"min_funding":{"type":"number"},"locations":{"type":"array","items":{"type":"string"}}},"description":"ICP criteria to match against. If not provided, uses default criteria."}},"required":["email_or_domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_export_leads","description":"Export leads in CSV, JSON, or Markdown format. Filter by campaign, minimum score, or status.","parameters":{"type":"object","properties":{"format":{"type":"string","enum":["csv","json","markdown"],"description":"Export format"},"campaign_id":{"type":"string","description":"Export only leads from this campaign"},"min_score":{"type":"number","minimum":0,"maximum":100,"description":"Minimum lead score"},"status":{"type":"string","enum":["new","contacted","qualified","nurturing","converted","lost"],"description":"Filter by lead status"}},"required":["format"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_manage_campaign","description":"Create, update, list, or get campaigns/lead lists. Campaigns organize leads for targeted outreach.","parameters":{"type":"object","properties":{"action":{"type":"string","enum":["create","update","list","get"],"description":"Action to perform"},"campaign_id":{"type":"string","description":"Campaign ID (required for update/get)"},"name":{"type":"string","description":"Campaign name (required for create)"},"description":{"type":"string","description":"Campaign description"},"status":{"type":"string","enum":["draft","active","paused","completed"],"description":"Campaign status"}},"required":["action"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_get_insights","description":"Get analytics and insights about your lead pipeline: conversion rates, lead flow, top sources, score distributions, and more.","parameters":{"type":"object","properties":{"campaign_id":{"type":"string","description":"Filter insights to a specific campaign"},"days":{"type":"number","minimum":1,"maximum":365,"description":"Time range in days"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_search_prospects","description":"Full-text search across leads and companies in the database. Search by name, email, company, domain, title, or description.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query"},"type":{"type":"string","enum":["leads","companies","all"],"description":"Search type"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Maximum results"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_get_lead_research","description":"Generate AI-ready research data about a lead including their profile, company details, enrichment data, and suggested talking points. Returns structured prompt data for further AI analysis.","parameters":{"type":"object","properties":{"email":{"type":"string","description":"Email of the lead to research"}},"required":["email"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid-prospect__prospect_status","description":"Get system health and status: lead count, company count, configured providers, enrichment statistics, and configuration summary.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
